import{_ as e,o as r,c as l,ag as s}from"./chunks/framework.DXGyWiRo.js";const n="/images/CA2add.png",a="/images/CS2lw.png",o="/images/CS2sw.png",d="/images/CS2beq.png",y=JSON.parse('{"title":"Computer Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"code/computer-architecture/basic.md","filePath":"code/computer-architecture/basic.md"}'),i={name:"code/computer-architecture/basic.md"};function g(c,t,p,h,u,m){return r(),l("div",null,[...t[0]||(t[0]=[s('<h1 id="computer-architecture" tabindex="-1">Computer Architecture <a class="header-anchor" href="#computer-architecture" aria-label="Permalink to &quot;Computer Architecture&quot;">​</a></h1><h2 id="processor-review" tabindex="-1">Processor Review <a class="header-anchor" href="#processor-review" aria-label="Permalink to &quot;Processor Review&quot;">​</a></h2><h3 id="clocking-review" tabindex="-1">Clocking Review <a class="header-anchor" href="#clocking-review" aria-label="Permalink to &quot;Clocking Review&quot;">​</a></h3><ul><li>Logic components <ol><li>Not gate 取反</li><li>And gate 全1才1</li><li>OR gate 有1就1</li><li>XOR gate 不同才1</li></ol></li></ul><p><strong>MUX（多路选择器）</strong>：两条路通向同一个点，MUX是&quot;门卫&quot;，由控制信号决定放哪条路。 <strong>Decoder（译码器）</strong>：输入N位 → 激活 2ᴺ 条输出线中的1条。就像&quot;收银台号码显示屏&quot;，输入哪个号，那个灯亮。 <strong>ALU</strong>：算术逻辑单元，接收两个32位操作数，由ALUOp控制做 加/减/与/或/比较 等操作。</p><h3 id="the-clock-signal-critical-path" tabindex="-1">The clock signal &amp;&amp; Critical Path <a class="header-anchor" href="#the-clock-signal-critical-path" aria-label="Permalink to &quot;The clock signal &amp;&amp; Critical Path&quot;">​</a></h3><p>时钟就像心跳：<strong>上升沿</strong>触发寄存器&quot;锁存&quot;数据，两次上升沿之间，数据在组合逻辑中传播。</p><p>关键规则：时钟周期 ≥ 电路中最长传播延迟（关键路径）</p><p><strong>例题</strong>： 下图有一个加法器(5ns)和一个MUX(5ns)串联。时钟能跑多快？ → 关键路径 = 5 + 5 = 10ns → 最高频率 = <strong>100 MHz</strong>（不是200MHz！）</p><p>![CA Critical Path](/images/CA Critical Path.png)</p><p>Critical Path:木桶效应——整个电路的速度由<strong>最慢路径</strong>决定，而不是最快路径。</p><blockquote><p><strong>关键路径决定时钟上限</strong> 很多人以为时钟频率由&quot;平均延迟&quot;决定，其实是由<strong>最慢那条路径</strong>决定的。木桶效应，一条慢路径拖累整个CPU。</p></blockquote><h3 id="mips-review" tabindex="-1">MIPS Review <a class="header-anchor" href="#mips-review" aria-label="Permalink to &quot;MIPS Review&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">RISC 精简指令集</th><th style="text-align:center;">CISC 复杂指令集</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>比喻</strong>：乐高积木 — 每块简单，组合无限</td><td style="text-align:center;"><strong>比喻</strong>：瑞士军刀 — 专用工具，功能强大</td></tr><tr><td style="text-align:center;">✅ 固定32位长度，易并行</td><td style="text-align:center;">✅ 代码密度高</td></tr><tr><td style="text-align:center;">✅ 便于流水线</td><td style="text-align:center;">✅ 专用指令效率高（如矩阵乘法</td></tr><tr><td style="text-align:center;">✅ 编译器友好</td><td style="text-align:center;">❌ 指令长度可变，难并行</td></tr><tr><td style="text-align:center;">❌ 代码量大（需更多指令完成复杂任务</td><td style="text-align:center;">❌ 解码复杂</td></tr><tr><td style="text-align:center;"><strong>代表</strong>：MIPS、ARM、RISC-V</td><td style="text-align:center;"><strong>代表</strong>：x86（先拆成µops再执行）</td></tr></tbody></table><p>🏆 谁赢了？以及为什么</p><p>通用计算：<strong>RISC 胜出</strong>（约1980年代）。原因三点：</p><ol><li><strong>摩尔定律</strong>：内存变便宜，代码密度不再是瓶颈</li><li><strong>流水线并行</strong>：RISC固定长度指令更容易同时处理多条</li><li><strong>编译器崛起</strong>：没人再手写汇编，专用指令失去优势</li></ol><p>但 CISC <strong>没有死</strong>！GPU的向量指令、TPU的矩阵乘法指令、NPU的激活函数——这些<strong>专用加速器</strong>本质上都是CISC思想的延续。</p><h3 id="single-cycle-cpu" tabindex="-1">Single cycle CPU <a class="header-anchor" href="#single-cycle-cpu" aria-label="Permalink to &quot;Single cycle CPU&quot;">​</a></h3><p>🖥 五阶段执行流程</p><p>每条指令依次经过：</p><p><strong>IF</strong> 取指 → <strong>ID</strong> 译码 → <strong>EX</strong> 执行(ALU) → <strong>MEM</strong> 访存 → <strong>WB</strong> 写回</p><p>📦 MIPS 三种指令格式（全32位）</p><p><strong>R格式</strong>（寄存器型）：op(6) | rs(5) | rt(5) | rd(5) | shamt(5) | funct(6) → 用于：add、sub、and、or、slt</p><p><strong>I格式</strong>（立即数型）：op(6) | rs(5) | rt(5) | immediate(16) → 用于：lw、sw、beq、addi</p><p><strong>J格式</strong>（跳转型）：op(6) | jump target(26) → 用于：j</p><p>助记：R=寄存器, I=立即数, J=跳转</p><p>🗂 关键寄存器速查</p><table tabindex="0"><thead><tr><th style="text-align:left;">寄存器</th><th style="text-align:left;">编号</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">$zero</td><td style="text-align:left;">0</td><td style="text-align:left;">永远是0（只读）</td></tr><tr><td style="text-align:left;">$v0-$v1</td><td style="text-align:left;">2-3</td><td style="text-align:left;">函数返回值</td></tr><tr><td style="text-align:left;">$a0-$a3</td><td style="text-align:left;">4-7</td><td style="text-align:left;">函数参数</td></tr><tr><td style="text-align:left;">$t0-$t9</td><td style="text-align:left;">8-25</td><td style="text-align:left;">临时变量（可被覆盖）</td></tr><tr><td style="text-align:left;">$s0-$s7</td><td style="text-align:left;">16-23</td><td style="text-align:left;">保存变量（调用后保留）</td></tr><tr><td style="text-align:left;">$sp</td><td style="text-align:left;">29</td><td style="text-align:left;">栈指针</td></tr><tr><td style="text-align:left;">$ra</td><td style="text-align:left;">31</td><td style="text-align:left;">返回地址</td></tr></tbody></table><p>💾 内存与加载/存储</p><p>MIPS是<strong>Load-Store架构</strong>：所有运算只能在寄存器之间做，要读写内存必须用 lw/sw。</p><p><code>lw $t0, 8($s4)</code> → 把地址*($s4+8)<em>处的数据读入$t0 <code>sw $t0, 12($s4)</code> → 把$t0的值写入地址</em>($s4+12)*</p><p>注意：sw中 $t0 是<strong>源</strong>，不是目的地！内存地址 = 基址寄存器 + 偏移量</p><h3 id="mini-mips" tabindex="-1">Mini MIPS <a class="header-anchor" href="#mini-mips" aria-label="Permalink to &quot;Mini MIPS&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">控制信号</th><th>作用</th><th>当前值</th></tr></thead><tbody><tr><td style="text-align:center;">RegWrite</td><td>允许写寄存器</td><td></td></tr><tr><td style="text-align:center;">RegDataSrc</td><td>写入来源（ALU/MEM）</td><td></td></tr><tr><td style="text-align:center;">ALUSrc</td><td>ALU第二操作数来源</td><td></td></tr><tr><td style="text-align:center;">ALUOp</td><td>ALU执行的操作</td><td></td></tr><tr><td style="text-align:center;">MemWrite</td><td>允许写内存</td><td></td></tr><tr><td style="text-align:center;">PCSrc</td><td>下一PC来源</td><td></td></tr></tbody></table><ol><li><p><code>add t0, t3, s0</code></p><p>RegWrite( ✅ enable) -&gt; ALUSrc(来自寄存器) -&gt; ALUOp(add) -&gt; PCSrc (PC + 4（顺序执行）)</p></li></ol><p><img src="'+n+'" alt="CA2add"></p><ol start="2"><li><p><code>lw s4, 12(s0)</code></p><p>RegWrite( ✅ enable) -&gt; ALUSrc(来自立即数(12)) -&gt; ALUOp(add（地址计算）) -&gt; PCSrc (PC + 4（顺序执行）)</p><p><img src="'+a+'" alt="CS2lw"></p></li><li><p><code>sw t3, 8(sp)</code></p><p>ALUSrc(来自立即数(8)) -&gt; ALUOp(add（地址计算）) -&gt;MemWrite(✅ enable) -&gt; PCSrc (PC + 4（顺序执行）)</p></li></ol><p><img src="'+o+'" alt="CS2sw"></p><ol start="4"><li><p><code>beq t0, t1, loop</code></p><p>ALUSrc(来自寄存器) -&gt; ALUOp(sub（作差比较）) -&gt; PCSrc (结果=0 → PC+4+imm；否则 → PC+4)</p></li></ol><p><img src="'+d+'" alt="CS2beq"></p><h3 id="multi-cycle-cpu" tabindex="-1">Multi-cycle CPU <a class="header-anchor" href="#multi-cycle-cpu" aria-label="Permalink to &quot;Multi-cycle CPU&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>阶段数</th><th>原因</th></tr></thead><tbody><tr><td>lw</td><td><strong>5</strong></td><td>IF → ID → EX → <strong>MEM</strong>（读内存）→ WB</td></tr><tr><td>add</td><td><strong>4</strong></td><td>IF → ID → EX → WB（<strong>跳过MEM</strong>）</td></tr><tr><td>sw</td><td><strong>4</strong></td><td>IF → ID → EX → MEM（<strong>跳过WB</strong>，不用写寄存器）</td></tr></tbody></table><p>lw 看起来像4步，是因为 WB 阶段&quot;回头&quot;用了 Register File，而 Register File 在图上只画了一个框。但它在时间上确实是第5个独立的阶段。</p><p>🚀 为什么单周期不够好？</p><p>单周期的致命缺陷：周期时间 = <strong>最慢指令</strong>的延迟（即 lw 的5个阶段）。 哪怕 add 只需要4个阶段，也得等5ns。如果99%的指令是 add，平均执行时间仍是5ns，毫无改善。（时钟信号是一个物理振荡器，它不认识指令，不知道当前在跑 lw 还是 add，它只会<strong>机械地、匀速地</strong>发出节拍。）</p><p>解决方案：多周期——每条指令跑<strong>自己需要的周期数</strong>，用锁存器在阶段间保存中间结果。</p><p>📊 性能计算示例</p><p>若每阶段1ns，lw=1%，add=99%：</p><p><strong>单周期</strong>：全部按5ns → 平均 = <strong>5.00 ns</strong><strong>多周期</strong>：lw×5ns + add×4ns = 0.01×5 + 0.99×4 = <strong>4.01 ns</strong></p><p>提升约 20%！这正是&quot;让每条指令按需付费&quot;的好处。</p><p>但还可以更好！ 多周期中，当一条指令在EX阶段时，IF/ID/MEM/WB都在<strong>空转</strong>。 这正是流水线(Pipeline)要解决的问题。</p>',52)])])}const b=e(i,[["render",g]]);export{y as __pageData,b as default};
